  1→import { windowOutlineOnWall, wallDirection } from '@/geometry/wallGeometry';
  2→import { perpendicular, scale, add } from '@/geometry/point';
  3→
  4→function StandardWindow({ info, wall }) {
  5→  const dir = wallDirection(wall);
  6→  const perp = perpendicular(dir);
  7→  const halfThick = wall.thickness / 2;
  8→
  9→  const lines = [-0.3, 0, 0.3].map(fraction => {
 10→    const offset = scale(perp, halfThick * fraction);
 11→    return {
 12→      x1: add(info.start, offset).x,
 13→      y1: add(info.start, offset).y,
 14→      x2: add(info.end, offset).x,
 15→      y2: add(info.end, offset).y,
 16→    };
 17→  });
 18→
 19→  return lines.map((l, i) => (
 20→    <line
 21→      key={i}
 22→      x1={l.x1} y1={l.y1}
 23→      x2={l.x2} y2={l.y2}
 24→      stroke="var(--color-wall-fill)"
 25→      strokeWidth={i === 1 ? 2 : 1}
 26→      vectorEffect="non-scaling-stroke"
 27→    />
 28→  ));
 29→}
 30→
 31→function CasementWindow({ win, info }) {
 32→  const angleDeg = (info.angle * 180) / Math.PI;
 33→  const flipSign = win.openDirection === 'right' ? -1 : 1;
 34→  const leafLen = win.width * 0.3;
 35→
 36→  return (
 37→    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
 38→      {/* Glass pane line */}
 39→      <line
 40→        x1={0} y1={0}
 41→        x2={win.width} y2={0}
 42→        stroke="var(--color-wall-fill)"
 43→        strokeWidth={2}
 44→        vectorEffect="non-scaling-stroke"
 45→      />
 46→      {/* Hinge leaf */}
 47→      <line
 48→        x1={0} y1={0}
 49→        x2={0} y2={flipSign * -leafLen}
 50→        stroke="var(--color-wall-fill)"
 51→        strokeWidth={1}
 52→        vectorEffect="non-scaling-stroke"
 53→      />
 54→      {/* Quarter-circle arc */}
 55→      <path
 56→        d={`M ${leafLen} 0 A ${leafLen} ${leafLen} 0 0 ${win.openDirection === 'left' ? 1 : 0} 0 ${flipSign * -leafLen}`}
 57→        fill="none"
 58→        stroke="var(--color-wall-fill)"
 59→        strokeWidth={1}
 60→        strokeDasharray="4 3"
 61→        vectorEffect="non-scaling-stroke"
 62→      />
 63→    </g>
 64→  );
 65→}
 66→
 67→function FixedWindow({ info }) {
 68→  return (
 69→    <>
 70→      {/* Center line */}
 71→      <line
 72→        x1={info.start.x} y1={info.start.y}
 73→        x2={info.end.x} y2={info.end.y}
 74→        stroke="var(--color-wall-fill)"
 75→        strokeWidth={2}
 76→        vectorEffect="non-scaling-stroke"
 77→      />
 78→      {/* Diagonal X: p1→p3 */}
 79→      <line
 80→        x1={info.p1.x} y1={info.p1.y}
 81→        x2={info.p3.x} y2={info.p3.y}
 82→        stroke="var(--color-wall-fill)"
 83→        strokeWidth={1}
 84→        vectorEffect="non-scaling-stroke"
 85→      />
 86→      {/* Diagonal X: p2→p4 */}
 87→      <line
 88→        x1={info.p2.x} y1={info.p2.y}
 89→        x2={info.p4.x} y2={info.p4.y}
 90→        stroke="var(--color-wall-fill)"
 91→        strokeWidth={1}
 92→        vectorEffect="non-scaling-stroke"
 93→      />
 94→    </>
 95→  );
 96→}
 97→
 98→export default function WindowRenderer({ windows, walls }) {
 99→  return (
100→    <g className="windows">
101→      {windows.map(win => {
102→        const wall = walls.find(w => w.id === win.wallId);
103→        if (!wall) return null;
104→
105→        const info = windowOutlineOnWall(wall, win);
106→        const type = win.type || 'standard';
107→
108→        return (
109→          <g key={win.id} data-id={win.id} data-type="window">
110→            {/* White rectangle to mask wall */}
111→            <polygon
112→              points={`${info.p1.x},${info.p1.y} ${info.p2.x},${info.p2.y} ${info.p3.x},${info.p3.y} ${info.p4.x},${info.p4.y}`}
113→              fill="white"
114→              stroke="none"
115→            />
116→            {type === 'standard' && <StandardWindow info={info} wall={wall} />}
117→            {type === 'casement' && <CasementWindow win={win} info={info} />}
118→            {type === 'fixed' && <FixedWindow info={info} />}
119→          </g>
120→        );
121→      })}
122→    </g>
123→  );
124→}
